package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithRecordSeparator() {
        // Given
        char recordSeparator = '|';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat updatedFormat = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        assertEquals(String.valueOf(recordSeparator), updatedFormat.getRecordSeparator());
    }

    @Test
    public void testWithRecordSeparatorUsingMock() {
        // Given
        char recordSeparator = '|';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Mocking the internal call to withRecordSeparator(String)
        CSVFormat mockedFormat = mock(CSVFormat.class);
        when(csvFormat.withRecordSeparator(String.valueOf(recordSeparator))).thenReturn(mockedFormat);

        // When
        CSVFormat updatedFormat = csvFormat.withRecordSeparator(recordSeparator);

        // Then
        assertEquals(mockedFormat, updatedFormat);
    }
}
